UPDATE bbs_users SET call_sign = (@n := @n + 1), avatar_url = NULL WHERE call_sign IS NULL OR call_sign = '' OR call_sign REGEXP '[^0-9]';
UPDATE bbs_users SET telegram_code = CONCAT('T', call_sign) WHERE telegram_code IS NULL OR telegram_code = '' OR telegram_code LIKE 'TG-%';

